// ── Template helpers ──────────────────────────────────────────────────────────

// workspaceFilterIsActive returns true when at least one filter dimension is set.
func workspaceFilterIsActive(f services.WorkspaceFilter) bool {
	return f.Domain != "" || f.Status != "" || f.TypeStr != "" ||
		f.HasAvailableHooks || f.NoAttempts || f.HasLinkedPayout
}

// workspacePageURL builds a pagination URL preserving the current filter params.
func workspacePageURL(vm InvestigationWorkspaceVM, page int) string {
	base := "/settings/payment-gateways/investigation?page=" + Itoa(page)
	f := vm.Filter
	if f.Domain != "" {
		base += "&domain=" + string(f.Domain)
	}
	if f.Status != "" {
		base += "&status=" + f.Status
	}
	if f.TypeStr != "" {
		base += "&type=" + f.TypeStr
	}
	if f.HasAvailableHooks {
		base += "&hooks=1"
	}
	if f.NoAttempts {
		base += "&no_attempts=1"
	}
	if f.HasLinkedPayout {
		base += "&has_payout=1"
	}
	return base
}

func workspaceNextPageURL(vm InvestigationWorkspaceVM) string {
	base := workspacePageURL(vm, vm.CurrentPage+1)
	if vm.NextCursor != "" {
		base += "&cursor=" + url.QueryEscape(vm.NextCursor)
	}
	return base
}

